{
    "level": "B2",
    "intro": "W tym temacie szczegółowo poznasz <strong>Future Continuous Passive</strong>. <strong>Ważne:</strong> ta forma jest bardzo rzadko używana w prawdziwej komunikacji ze względu na jej niewygodną konstrukcję.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "<strong>Temat + będzie + V3</strong>:",
            "example": "The house will be being painted at this time tomorrow."
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "text": "<strong>Temat + nie będzie + V3</strong>:",
            "example": "The report will not be being written at that moment."
        },
        {
            "label": "⚠️Uwaga",
            "color": "amber",
            "text": "Ten formularz jest <strong>rzadko używany</strong>!",
            "example": "Краще: The house will be painted tomorrow."
        }
    ]
}

{
    "title": "1. Struktura przyszłości ciągłej biernej",
    "intro": "Wzór: <strong>będzie + będzie + będzie + V3</strong>. Ta struktura jest niewygodna, dlatego jest rzadko używana:",
    "items": [
        {
            "label": "Wszystkie osoby",
            "title": "będzie + V3",
            "subtitle": "Ja/Ty/On/Ona/To/My/Oni będziemy przeprowadzać wywiad."
        },
        {
            "label": "Liczba pojedyncza",
            "title": "będzie + V3",
            "subtitle": "Samochód zostanie naprawiony. - Samochód zostanie naprawiony."
        },
        {
            "label": "Mnogi",
            "title": "będzie + V3",
            "subtitle": "Dokumenty zostaną rozpatrzone. — Dokumenty zostaną rozpatrzone."
        },
        {
            "label": "⚠️Rzadko!",
            "title": "Lepiej unikać",
            "subtitle": "Zwykle zastępowany przez Future Simple Passive."
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Kolejność słów: <strong>Temat + będzie + V3</strong>",
            "examples": [
                {
                    "en": "The house will be being painted at this time tomorrow.",
                    "ua": "Jutro o tej porze dom będzie malowany."
                },
                {
                    "en": "The project will be being discussed at 3 PM.",
                    "ua": "Projekt będzie omawiany o godz. 15:00."
                },
                {
                    "en": "The documents will be being reviewed all day.",
                    "ua": "Dokumenty będą przeglądane przez cały dzień."
                }
            ]
        },
        {
            "label": "⚠️Praktyczne porady",
            "color": "amber",
            "description": "<strong>Lepiej używać Future Simple Passive lub stanu aktywnego</strong>:",
            "examples": [
                {
                    "en": "Instead: The house will be painted tomorrow.",
                    "ua": "Lepiej: Dom zostanie pomalowany jutro."
                },
                {
                    "en": "Or active: They will be painting the house.",
                    "ua": "Lub aktywni: pomalują dom."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy (w teorii) używać strony biernej Future Continuous?",
    "sections": [
        {
            "label": "Ciągłe działanie w przyszłej chwili",
            "color": "emerald",
            "description": "Aby podkreślić, że czynność będzie <strong>kontynuowana w określonym momencie</strong>:",
            "examples": [
                {
                    "en": "At 10 AM tomorrow, the meeting will be being held.",
                    "ua": "Spotkanie odbędzie się jutro o godzinie 10:00."
                },
                {
                    "en": "This time next week, the building will be being renovated.",
                    "ua": "W przyszłym tygodniu o tej porze w budynku będą prowadzone prace remontowe."
                }
            ]
        },
        {
            "label": "Dlaczego warto unikać tej formy?",
            "color": "rose",
            "description": "Powody, dla których ten formularz jest <strong>rzadko używany</strong>:",
            "examples": [
                {
                    "en": "Too awkward: \"will be being\" sounds clumsy.",
                    "ua": "Zbyt niezręczne: „będzie” brzmi niezręcznie."
                },
                {
                    "en": "Confusing: Three verb forms in a row (be being done).",
                    "ua": "Zdezorientowany: Trzy formy czasownika z rzędu."
                },
                {
                    "en": "Easier alternatives exist.",
                    "ua": "Istnieją prostsze alternatywy."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po will: <strong>Temat + nie będzie + V3</strong>",
            "examples": [
                {
                    "en": "The report will not be being written at that moment.",
                    "ua": "W tym czasie raport nie będzie pisany."
                },
                {
                    "en": "The car will not be being repaired tomorrow afternoon.",
                    "ua": "Jutro po południu samochód nie będzie naprawiony."
                }
            ]
        },
        {
            "label": "Skrócona forma",
            "color": "amber",
            "description": "Potoczne: <strong>nie będę</strong> (jeszcze bardziej niezwykłe)",
            "examples": [
                {
                    "en": "The documents won't be being processed then.",
                    "ua": "Dokumenty nie będą wówczas przetwarzane."
                }
            ]
        }
    ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytanie Tak/Nie",
            "color": "blue",
            "description": "<strong>Czy + Temat + będzie + V3?</strong>",
            "examples": [
                {
                    "en": "Will the house be being painted at that time?",
                    "ua": "Czy w tym czasie dom będzie malowany?"
                },
                {
                    "en": "Will the project be being discussed tomorrow?",
                    "ua": "Czy projekt będzie jutro omawiany?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Jakie-słowo + będzie + Temat + będzie + V3?</strong>",
            "examples": [
                {
                    "en": "What will be being done at 5 PM?",
                    "ua": "Co będą robić o 17:00?"
                },
                {
                    "en": "Where will the meeting be being held?",
                    "ua": "Gdzie odbędzie się spotkanie?"
                }
            ]
        }
    ]
}

{
    "title": "6. Lepsze alternatywy",
    "intro": "Zamiast Future Continuous Passive lepiej jest użyć:",
    "rows": [
        {
            "en": "❌ The house will be being painted.",
            "ua": "(niezgrabnie)",
            "note": "✅ The house will be painted. (Future Simple Passive)"
        },
        {
            "en": "❌ The report will be being written.",
            "ua": "(za trudne)",
            "note": "✅ They will be writing the report. (Future Continuous Active)"
        },
        {
            "en": "❌ The car will be being repaired.",
            "ua": "(trudno wymówić)",
            "note": "✅ The car will be repaired. / The car is going to be repaired."
        }
    ],
    "warning": "📌 W 99% przypadków lepiej jest zastosować Future Simple Passive lub Future Continuous Active!"
}

{
    "title": "7. Aktywny kontra pasywny ─ Future Continuous",
    "intro": "Porównanie stanu aktywnego i pasywnego:",
    "rows": [
        {
            "en": "Active: They will be painting the house.",
            "ua": "Pomalują dom.",
            "note": "→ Pasywne: Dom będzie malowany. (рідко)"
        },
        {
            "en": "Active: We will be discussing the project.",
            "ua": "Omówimy projekt.",
            "note": "→ Pasywny: Projekt będzie omawiany. (рідко)"
        },
        {
            "en": "Active: Someone will be repairing the car.",
            "ua": "Ktoś naprawi samochód.",
            "note": "→ Pasywne: Samochód będzie naprawiany. (рідко)"
        }
    ],
    "warning": "📌 Future Continuous Aktywny stan brzmi znacznie bardziej naturalnie!"
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomiń bycie.",
            "wrong": "The house will be painted now. (якщо потрібен Continuous)",
            "right": "✅ The house will be being painted now. (або краще: is being painted)"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zła kolejność.",
            "wrong": "The report will being be written.",
            "right": "✅ The report will be being written."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Używanie bycia zamiast bycia.",
            "wrong": "The car will be been repaired.",
            "right": "✅ The car will be being repaired."
        },
        {
            "label": "Rada",
            "color": "emerald",
            "title": "Lepsza strategia.",
            "wrong": "Намагатися використовувати Future Continuous Passive.",
            "right": "✅ Використовувати Future Simple Passive або Active."
        }
    ]
}
